"use client"

/**
 * The dashboard's hero number — clients with documents still outstanding —
 * remixable by Vendo (06-apps §8).
 *
 * Deliberately self-contained (React only, inline styles) so `vendo sync`
 * static capture reproduces it faithfully inside the sandboxed jail, whose
 * module space is React plus captured sub-sources and whose CSS is the
 * captured app-root stylesheet, not the compiled Tailwind bundle. The values
 * mirror the Cadence brand tokens in `src/app/globals.css`.
 */

const EVERGREEN_800 = "#1c4339"
const EVERGREEN_900 = "#16362e"
const EVERGREEN_950 = "#0b211c"
const EVERGREEN_100 = "#d8ebe2"
const STATUS_MISSING = "#b45309"
const STATUS_MISSING_BG = "#fdf0df"
const FONT = 'var(--font-hanken, system-ui), ui-sans-serif, system-ui, sans-serif'

export interface MissingDocsHeroProps {
  /** Clients with at least one outstanding (missing/rejected) document. */
  missingCount: number
  /** All active clients. */
  clientCount: number
  badgeLabel?: string
}

export function MissingDocsHero({
  missingCount,
  clientCount,
  badgeLabel = "Action needed",
}: MissingDocsHeroProps) {
  return (
    <article
      style={{
        borderRadius: 12,
        border: `1px solid ${EVERGREEN_900}`,
        background: `linear-gradient(to bottom right, ${EVERGREEN_800}, ${EVERGREEN_950})`,
        boxShadow: "0 1px 2px rgba(34,30,25,0.05), 0 1px 3px rgba(34,30,25,0.03)",
        padding: 20,
        fontFamily: FONT,
      }}
    >
      <p
        style={{
          margin: 0,
          fontSize: 13,
          fontWeight: 500,
          whiteSpace: "nowrap",
          color: "rgba(216,235,226,0.8)",
        }}
      >
        Clients missing documents
      </p>
      <div
        style={{
          marginTop: 12,
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          gap: 12,
        }}
      >
        <span
          style={{
            fontSize: 40,
            lineHeight: 1,
            fontWeight: 600,
            letterSpacing: "-0.025em",
            color: "#ffffff",
            fontVariantNumeric: "tabular-nums",
          }}
        >
          {missingCount}
        </span>
        <span
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: 6,
            borderRadius: 9999,
            padding: "2px 8px",
            fontSize: 11,
            fontWeight: 500,
            whiteSpace: "nowrap",
            background: STATUS_MISSING_BG,
            color: STATUS_MISSING,
          }}
        >
          <span
            aria-hidden
            style={{
              width: 6,
              height: 6,
              borderRadius: 9999,
              background: "currentcolor",
            }}
          />
          {badgeLabel}
        </span>
      </div>
      <p
        style={{
          margin: "10px 0 0",
          fontSize: 12,
          color: `${EVERGREEN_100}99`,
        }}
      >
        of {clientCount} active clients need chasing
      </p>
    </article>
  )
}

// The jail's module loader renders a fork's DEFAULT export (08-ui §5), so a
// remixable component must carry one; the named export stays for host imports.
export default MissingDocsHero

styles.css:
@import "tailwindcss";

/* Cadence design tokens.
   Brand: deep evergreen primary on warm paper neutrals; status colors are
   reserved exclusively for document/deadline state (missing = amber/red,
   in review = blue, verified/complete = green). Light theme only. */

@theme inline {
  --font-sans: var(--font-hanken), ui-sans-serif, system-ui, sans-serif;
  --font-mono: var(--font-spline-mono), ui-monospace, "SF Mono", monospace;
}

@theme {
  /* Brand — evergreen */
  --color-evergreen-50: #eef6f2;
  --color-evergreen-100: #d8ebe2;
  --color-evergreen-200: #b3d8c8;
  --color-evergreen-300: #85bda8;
  --color-evergreen-400: #559e85;
  --color-evergreen-500: #34816a;
  --color-evergreen-600: #266755;
  --color-evergreen-700: #205345;
  --color-evergreen-800: #1c4339;
  --color-evergreen-900: #16362e;
  --color-evergreen-950: #0b211c;

  /* Warm neutral surfaces & ink */
  --color-surface: #f7f5f1;
  --color-card: #ffffff;
  --color-line: #e9e4db;
  --color-line-strong: #d9d2c6;
  --color-ink: #221e19;
  --color-ink-soft: #5c554b;
  --color-ink-faint: #7d7468;

  /* Status — document/deadline state only */
  --color-status-missing: #b45309;
  --color-status-missing-bg: #fdf0df;
  --color-status-overdue: #b91c1c;
  --color-status-overdue-bg: #fdeae8;
  --color-status-review: #1d4ed8;
  --color-status-review-bg: #e8eefc;
  --color-status-verified: #047857;
  --color-status-verified-bg: #e2f5ec;

  /* Elevation — warm-tinted, never pure black */
  --shadow-card: 0 1px 2px rgb(34 30 25 / 0.05), 0 1px 3px rgb(34 30 25 / 0.03);
  --shadow-pop: 0 1px 3px rgb(34 30 25 / 0.05), 0 8px 24px rgb(34 30 25 / 0.08);
}

body {
  background-color: var(--color-surface);
  color: var(--color-ink);
  font-family: var(--font-sans);
  -webkit-font-smoothing: antialiased;
}

::selection {
  background-color: var(--color-evergreen-200);
}

/* Vendo stage approval: the shell's ApprovalCard materializes in-flow
   beneath the generated view (same consent surface as the chat path). */
.cadence-approval-inflow .fl-approval { animation: cadence-approval-in 0.28s cubic-bezier(0.16, 1, 0.3, 1); }
@keyframes cadence-approval-in { from { opacity: 0; transform: translateY(6px); } to { opacity: 1; transform: none; } }
